DROP TABLE IF EXISTS products;
DROP TABLE IF EXISTS users;
DROP TABLE IF EXISTS orders;
DROP TABLE IF EXISTS wishlist;
CREATE TABLE products (id SERIAL PRIMARY KEY, name TEXT, category TEXT, price INTEGER, description TEXT, image_url TEXT, tags TEXT, specs TEXT);
CREATE TABLE users (id SERIAL PRIMARY KEY, username TEXT UNIQUE NOT NULL, password TEXT NOT NULL);
CREATE TABLE orders (id SERIAL PRIMARY KEY, user_id INTEGER, items TEXT, total INTEGER, status TEXT, date TIMESTAMP DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE wishlist (id SERIAL PRIMARY KEY, user_id INTEGER, product_id INTEGER, created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP);
